using System;\nusing System.IO;\nusing System.Reflection;\nusing System.Web;\nusing System.Web.Security;\nusing Moq;\nusing OWASP.WebGoat.NET.WebGoatCoins;\nusing OWASP.WebGoat.NET.App_Code.DB;\nusing Xunit;\n\nnamespace OWASP.WebGoat.NET.WebGoatCoins.Tests\n{\n    public class CustomerLoginCookieFlagsTests\n    {\n        [Fact]\n        public void ButtonLogOnClick_SetsAuthCookie_HttpOnlyEnabled()\n        {\n            // Arrange\n            var page = new CustomerLogin();\n\n            var mockDb = new Mock<IDbProvider>();\n            mockDb.Setup(d => d.IsValidCustomerLogin(It.IsAny<string>(), It.IsAny<string>())).Returns(true);\n\n            var duField = typeof(CustomerLogin).GetField(\"du\", BindingFlags.Instance | BindingFlags.NonPublic);\n            Assert.NotNull(duField);\n            duField!.SetValue(page, mockDb.Object);\n\n            // Setup HttpContext for Request/Response\n            var httpCtx = new HttpContext(\n                new HttpRequest(\"\", \"http://localhost/\", \"\"),\n                new HttpResponse(new StringWriter()));\n            HttpContext.Current = httpCtx;\n\n            // Provide required controls\n            SetPrivateControl(page, \"txtUserName\", new System.Web.UI.WebControls.TextBox { Text = \"a@b.com\" });\n            SetPrivateControl(page, \"txtPassword\", new System.Web.UI.WebControls.TextBox { Text = \"pw\" });\n            SetPrivateControl(page, \"PanelError\", new System.Web.UI.WebControls.Panel());\n            SetPrivateControl(page, \"labelError\", new System.Web.UI.WebControls.Label());\n\n            // Act\n            InvokeNonPublic(page, \"ButtonLogOn_Click\", page, EventArgs.Empty);\n\n            // Assert\n            var authCookie = httpCtx.Response.Cookies[FormsAuthentication.FormsCookieName];\n            Assert.NotNull(authCookie);\n            Assert.True(authCookie!.HttpOnly);\n        }\n\n        private static void SetPrivateControl(object page, string fieldName, object control)\n        {\n            var f = page.GetType().GetField(fieldName, BindingFlags.Instance | BindingFlags.NonPublic);\n            Assert.NotNull(f);\n            f!.SetValue(page, control);\n        }\n\n        private static void InvokeNonPublic(object obj, string methodName, params object[] args)\n        {\n            var m = obj.GetType().GetMethod(methodName, BindingFlags.Instance | BindingFlags.NonPublic);\n            Assert.NotNull(m);\n            m!.Invoke(obj, args);\n        }\n    }\n}\n